comment:
/**
	 * Returns the width of the current drawing.
	 *
	 * ## Try it
	 * 
	 * ```js use-document-builder
	 * builder.CreateFile("docx");
	 * var oDocument = Api.GetDocument();
	 * var oParagraph = oDocument.GetElement(0);
	 * var oGs1 = Api.CreateGradientStop(Api.CreateRGBColor(255, 213, 191), 0);
	 * var oGs2 = Api.CreateGradientStop(Api.CreateRGBColor(255, 111, 61), 100000);
	 * var oFill = Api.CreateLinearGradientFill([oGs1, oGs2], 5400000);
	 * var oStroke = Api.CreateStroke(0, Api.CreateNoFill());
	 * var oDrawing = Api.CreateShape("rect", 100 * 36000, 10 * 36000, oFill, oStroke);
	 * oParagraph.AddDrawing(oDrawing);
	 * var nWidth = oDrawing.GetWidth();
	 * var oDocContent = oDrawing.GetContent();
	 * oParagraph = Api.CreateParagraph();
	 * oParagraph.AddText("Drawing width: " + nWidth / 36000 + " mm");
	 * oDocContent.AddElement(0, oParagraph);
	 * builder.SaveFile("docx", "GetWidth.docx");
	 * builder.CloseFile();
	 * ```
	 *
	 * @memberof ApiDrawing
	 * @returns {EMU}
	 */

description:
Returns the width of the current drawing.

## Try it

```js use-document-builder
builder.CreateFile("pptx");
var oPresentation = Api.GetPresentation();
var oSlide = oPresentation.GetSlideByIndex(0);
oSlide.RemoveAllObjects();
var oFill = Api.CreateSolidFill(Api.CreateRGBColor(255, 111, 61));
var oStroke = Api.CreateStroke(0, Api.CreateNoFill());
var oShape = Api.CreateShape("flowChartMagneticTape", 300 * 36000, 130 * 36000, oFill, oStroke);
oShape.SetPosition(608400, 1267200);
var nWidth = oShape.GetWidth();
var oDocContent = oShape.GetDocContent();
var oParagraph = oDocContent.GetElement(0);
oParagraph.AddText("Drawing width: " + nWidth);
oSlide.AddObject(oShape);
builder.SaveFile("pptx", "GetWidth.pptx");
builder.CloseFile();
```

## Try it

```js use-document-builder
builder.CreateFile("docx");
var oDocument = Api.GetDocument();
var oParagraph = oDocument.GetElement(0);
