	 *   var sFormatString = "";
	 *   for (let nTempLvl = 1; nTempLvl <= (nLvl + 1); ++nTempLvl) sFormatString += "%" + nTempLvl + ".";
	 *   oNumLvl.SetCustomType("lowerRoman", sFormatString, "left");
